#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
vector<int>e[155];
//f[u][k] 表示在以u为根的子树中，保留k个节点，最少需要删除多少条边
int n,p,u,v,f[155][155],sz[155],ans;
int dfs(int u)
{
	sz[u]=1;
	FOI(v,e[u])
	{
		int s=dfs(v);
		ROF(j,sz[u],1)
		{
			FOR(k,1,s)
			{
				if(j+k>p)break;
				f[u][j+k]=min(f[u][j+k],f[u][j]+f[v][k]-1);
			}
		}
		sz[u]+=s;
	}
	return sz[u];
}
signed main(void)
{
	IOS
	cin>>n>>p;
	FOR(i,1,n-1)
	{
		cin>>u>>v;
		e[u].pb(v);
	}
	FOR(i,1,n)
	{
		FOR(j,1,p)f[i][j]=inf;
		f[i][1]=(int)e[i].size();
	}
	dfs(1);
	ans=f[1][p];
	FOR(i,1,n)
	{
		if(f[i][p]<ans)ans=f[i][p]+1;
	}
	cout<<ans; 
	return false;
}
